sys_ui_policy.script_false:
function onCondition() {	
	// active always false
	g_form.setDisplay("active", false);

	// KT | STRY0048463	
	g_form.setMandatory("u_signature_instructions", false);
	g_form.setReadOnly("u_signature_instructions", true);
	g_form.setDisplay("u_signature_instructions", false);
	g_form.setSectionDisplay("signature", false);
}

sys_ui_policy.script_true:
function onCondition() {
	var type = g_form.getValue("tasker_type");

		// KT | STRY0048463
		g_form.setSectionDisplay("signature", false);
		g_form.setDisplay("u_signature_instructions", true);

		//get taskOwner, reviewer and active
		var reviewer = g_form.getValue("u_reviewer");
		var taskOwner = g_form.getValue("u_task_requester");
		var isActive = g_form.getValue("active");

		if(isActive == "true" && (g_user.userID == reviewer || g_user.userID == taskOwner || g_user.userID == taskOwner == "")) {
			g_form.setReadOnly("u_signature_instructions", false);
			g_form.setMandatory("u_signature_instructions", true);
		}	
}
